        BufferedWriter writer = new BufferedWriter(new FileWriter(fileDst));
        writer.append("package " + packageName + ";\n");
        String line = "";
        while ((line = reader.readLine()) != null) writer.append(line + "\n");
        writer.flush();
        writer.close();
        reader.close();
    }
}

