            do {
                read = reader.read(buffer);
                if (read > 0) {
                    out.write(buffer, 0, read);
                }
            } while (read != -1);
            out.flush();
            out.close();
        } else {
            printUsage("Format not specified via argument -f. Also guessing for the extension of input file " + inputFile.getName() + " failed");
        }
    } catch (Exception ex) {
        ex.printStackTrace();
        printUsage(ex.getMessage());
    }
}

