    } catch (IOException e) {
        Status status = new Status(Status.ERROR, ImageUI.PLUGIN_ID, "IO Error", e);
        throw new CoreException(status);
    } finally {
        if (in != null) {
            try {
                in.close();
            } catch (IOException e) {
            }
        }
    }
    super.setInput(input);
}

