                    inputStream.close();
                    OutputStream outputStream = classFile.getOutputStream();
                    outputStream.write(b);
                    outputStream.close();
                    injectedClasses++;
                }
            } catch (IllegalStateException e) {
            }
            newSize += classFile.getSize();
